def get_target_for_redirect(target: str, domain: str) -> str:
    from urllib.parse import urlparse

    # Normalize inputs
    domain = domain.strip().lower()
    if not domain:
        return "https://"

    parsed = urlparse(target)
    # If target lacks a network location, treat as invalid and fallback
    if not parsed.netloc:
        return f"https://{domain}"

    # Extract hostname, stripping possible port
    hostname = parsed.netloc.lower().split(":")[0]

    # Determine if hostname matches domain or is a subdomain thereof
    if hostname == domain or hostname.endswith("." + domain):
        # Force HTTPS scheme while preserving the rest of the URL
        secure_parsed = parsed._replace(scheme="https")
        return secure_parsed.geturl()
    else:
        return f"https://{domain}"

