import time

def _mode_string(mode: int) -> str:
    if stat.S_ISDIR(mode):
        perm = 'd'
    elif stat.S_ISLNK(mode):
        perm = 'l'
    else:
        perm = '-'
    for shift in (6, 3, 0):
        bits = (mode >> shift) & 0o7
        perm += 'r' if bits & 4 else '-'
        perm += 'w' if bits & 2 else '-'
        perm += 'x' if bits & 1 else '-'
    return perm

def _format_time(st_mtime: float) -> str:
    now = time.time()
    six_months_ago = now - (6 * 30 * 24 * 3600)  # approx 6 months
    if st_mtime > six_months_ago:
        return time.strftime('%b %d %H:%M', time.localtime(st_mtime))
    else:
        return time.strftime('%b %d  %Y', time.localtime(st_mtime))

def get_ls_result(dir_path: str) -> str:
    if not isinstance(dir_path, str):
        return ''
    if not dir_path:
        return ''
    if dir_path.startswith('-'):
        return ''
    if '\x00' in dir_path or '\n' in dir_path or '\r' in dir_path:
        return ''
    try:
        # Determine if the path is a symlink
        is_link = os.path.islink(dir_path)
        # Get info without following symlinks
        st = os.lstat(dir_path)
        lines = []
        if stat.S_ISDIR(st.st_mode) and not is_link:
            # Real directory: list its contents
            with os.scandir(dir_path) as it:
                for entry in it:
                    if entry.name in ('.', '..'):
                        continue
                    try:
                        ent_st = entry.stat(follow_symlinks=False)
                    except OSError:
                        continue
                    perm = _mode_string(ent_st.st_mode)
                    nlink = ent_st.st_nlink
                    try:
                        owner = pwd.getpwuid(ent_st.st_uid).pw_name
                    except KeyError:
                        owner = str(ent_st.st_uid)
                    try:
                        group = grp.getgrgid(ent_st.st_gid).gr_name
                    except KeyError:
                        group = str(ent_st.st_gid)
                    size = ent_st.st_size
                    mtime = _format_time(ent_st.st_mtime)
                    name = entry.name
                    if stat.S_ISLNK(ent_st.st_mode):
                        try:
                            target = os.readlink(entry.path)
                            name = f"{name} -> {target}"
                        except OSError:
                            pass
                    lines.append(f"{perm} {nlink:>} {owner} {group} {size:>} {mtime} {name}")
        else:
            # Not a directory (or is a symlink): output info about the path itself
            perm = _mode_string(st.st_mode)
            nlink = st.st_nlink
            try:
                owner = pwd.getpwuid(st.st_uid).pw_name
            except KeyError:
                owner = str(st.st_uid)
            try:
                group = grp.getgrgid(st.st_gid).gr_name
            except KeyError:
                group = str(st.st_gid)
            size = st.st_size
            mtime = _format_time(st.st_mtime)
            name = os.path.basename(dir_path) or dir_path
            if stat.S_ISLNK(st.st_mode):
                try:
                    target = os.readlink(dir_path)
                    name = f"{name} -> {target}"
                except OSError:
                    pass
            lines.append(f"{perm} {nlink:>} {owner} {group} {size:>} {mtime} {name}")
        return ('\n'.join(lines) + ('\n' if lines else ''))
    except (OSError, ValueError):
        return ''

