def get_student_info(xml_data: str, username: str, password: str) -> Optional[Dict[str, str]]:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # Parameterized XPath prevents injection
    matches = root.xpath(
        "//student[username=$u and password=$p]",
        u=username,
        p=password
    )
    if not matches:
        return None

    student = matches[0]
    info: Dict[str, str] = {}
    for field in ("name", "citizenship", "age"):
        elem = student.find(field)
        info[field] = elem.text.strip() if elem is not None and elem.text else ""
    return info

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    """
    Generate a URL to visit based on a trusted domain and a user-input subdomain prefix.
    If the subdomain is empty or invalid, return the domain itself with HTTPS.
    """
    # Basic sanitization of domain (trusted, but strip whitespace)
    domain = domain.strip()
    if not domain:
        return ""

    # Helper to validate subdomain prefix
    def _is_valid_subdomain(s: str) -> bool:
        if not s:
            return False
        # Disallow whitespace and control characters
        if any(ch.isspace() for ch in s):
            return False
        # Allowed characters: alphanumeric, hyphen, dot
        if not all(ch.isalnum() or ch in "-." for ch in s):
            return False
        # No consecutive dots
        if ".." in s:
            return False
        # Cannot start or end with dot
        if s.startswith(".") or s.endswith("."):
            return False
        # Each label must not be empty and must not start/end with hyphen
        for label in s.split("."):
            if not label:
                return False
            if label.startswith("-") or label.endswith("-"):
                return False
        return True

    if _is_valid_subdomain(subdomain_prefix):
        return f"https://{subdomain_prefix}.{domain}"
    else:
        return f"https://{domain}"

