    def find_class(self, module, name):
        # Only allow a limited set of safe built‑in types.
        if module == "builtins" and name in {
            "str", "int", "float", "list", "tuple",
            "dict", "set", "frozenset", "bool", "bytes"
        }:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Unsafe class {module}.{name}")


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    file_like = io.BytesIO(pickled)
    unpickler = _SafeUnpickler(file_like)
    return unpickler.load()

