def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    # Extract AuthToken header (case‑insensitive handling)
    if isinstance(headers, dict):
        auth_header = headers.get('AuthToken')
    else:
        auth_header = getattr(headers, 'AuthToken', None)
    if not auth_header:
        return None

    # Decode base64
    try:
        if isinstance(auth_header, str):
            auth_header = auth_header.encode('utf-8')
        decoded = base64.b64decode(auth_header)
    except Exception:
        return None

    # Restricted unpickler to avoid arbitrary code execution
    class SafeUnpickler(cPickle.Unpickler):
        def find_class(self, module, name):
            # Only allow a limited set of built‑in types
            if module == 'builtins' and name in ('list', 'dict', 'tuple', 'str', 'int', 'float', 'bool', 'NoneType'):
                return getattr(__builtins__, name)
            raise cPickle.UnpicklingError(f"Unsafe class {module}.{name}")

    try:
        token = SafeUnpickler(io.BytesIO(decoded)).load()
    except Exception:
        return None

    # Determine validity and extract data
    if isinstance(token, dict):
        if token.get('valid') is True:
            return token.get('data')
    elif hasattr(token, 'valid') and getattr(token, 'valid', False):
        return getattr(token, 'data', None)

