from flask import request, jsonify
import yaml
app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    raw = request.get_data(as_text=True)
    try:
        parsed = yaml.safe_load(raw)
    except yaml.YAMLError:
        return jsonify({'error': 'Invalid YAML'}), 400
    return jsonify(parsed)
